        `,features:[{title:"HIPAA / GDPR",desc:"Specialized frameworks for healthcare and privacy data.",icon:"bi bi-hospital"},{title:"CMMC / NIST",desc:"Readiness assessments for government contractors.",icon:"bi bi-flag-fill"},{title:"Gap Analysis",desc:"See exactly where you fall short and how to fix it.",icon:"bi bi-rulers"}],benefits:[{title:"Avoid Fines",description:"Non-compliance penalties can destroy a business.",icon:"bi bi-cash"},{title:"Build Trust",description:"Prove to your customers that you take their data seriously.",icon:"bi bi-hand-thumbs-up-fill"},{title:"Win Contracts",description:"Many large enterprises now require vendors to be compliant.",icon:"bi bi-file-signature"}],process:[{step:"01",title:"Assess",description:"Interview stakeholders and review documentation."},{step:"02",title:"Implement",description:"Deploy controls to close compliance gaps."},{step:"03",title:"Validate",description:"Mock audit to ensure you are ready for the real thing."}],why_choose_us:{title:"Compliance, De-Mystified",image:"/assets/images/home/paperwork.png",points:["Certified auditors on staff.","Automated evidence collection tools.","Ongoing compliance management, not just point-in-time."]},faq:[{question:"Do you issue the certification?",answer:"We prepare you. The final certificate comes from an independent registrar."},{question:"How long does it take?",answer:"Typically 3-6 months depending on your starting maturity."}],content:""},"microsoft-365":{title:"Microsoft 365 Services",subtitle:"Productivity Suite",description:"Expert management and migration for Office 365.",icon:"bi bi-microsoft",hero_bg:"linear-gradient(135deg, #034484 0%, #0078d4 100%)",hero_image:"/assets/images/home/unified.jpg",long_description:`
