        `,features:[{title:"Cost Optimization",desc:"Analyze usage patterns to right-size instances and stop overpaying.",icon:"bi bi-cash-stack"},{title:"Site Reliability",desc:"Auto-scaling and load balancing implementation for 99.99% uptime.",icon:"bi bi-activity"},{title:"DevOps",desc:"CI/CD pipeline setup to accelerate your software delivery.",icon:"bi bi-infinity"}],benefits:[{title:"Agility",description:"Spin up new resources in minutes, not weeks.",icon:"bi bi-lightning-fill"},{title:"Security",description:"Cloud-native security controls often exceed on-premise capabilities.",icon:"bi bi-lock-fill"},{title:"Global Reach",description:"Deploy your application to regions closer to your users.",icon:"bi bi-globe"}],process:[{step:"01",title:"Design",description:"Architect a solution based on the Well-Architected Framework."},{step:"02",title:"Build",description:"Deploy infrastructure as code (Terraform/CloudFormation)."},{step:"03",title:"Manage",description:"Ongoing monitoring and specialized support."}],why_choose_us:{title:"Cloud Certified",image:"/assets/images/home/server-room.png",points:["Certified Architect-level engineers.","Vendor-neutral advice (we support both AWS and Azure).","proven track record of 30% average cost savings."]},faq:[{question:"Which cloud is better?",answer:"It depends on your workload. We help you choose the right fit."},{question:"Is the cloud secure?",answer:"Yes, if configured correctly. Security is our top priority."}],content:""},"workflow-automation":{title:"Workflow Automation",subtitle:"Streamline Operations",description:"Eliminate manual bottlenecks with intelligent process automation.",icon:"bi bi-robot",hero_bg:"linear-gradient(135deg, #0f172a 0%, #3b82f6 100%)",hero_image:"/assets/images/home/unified.jpg",long_description:`
