        `,features:[{title:"Value Stream Mapping",desc:"Visualizing end-to-end processes to identify non-value-added activities.",icon:"bi bi-map"},{title:"Gap Analysis",desc:"Comparing current performance against desired future state and industry benchmarks.",icon:"bi bi-rulers"},{title:"Compliance Check",desc:"Verifying that processes adhere to regulatory and internal policy requirements.",icon:"bi bi-check-circle"}],benefits:[{title:"Cost Reduction",desc:"Eliminate waste and redundancy to improve the bottom line.",icon:"bi bi-cash-stack"},{title:"Risk Mitigation",desc:"Identify and close control gaps in financial and operational processes.",icon:"bi bi-exclamation-triangle"},{title:"Standardization",desc:"Ensure consistent quality and predictable outcomes across the organization.",icon:"bi bi-layout-text-window-reverse"}],process:[{step:"01",title:"Interview",desc:'Stakeholder interviews and "gemba walks" to observe work as done.'},{step:"02",title:"Analyze",desc:"Data analysis and process modeling to verify findings."},{step:"03",title:"Report",desc:"Detailed findings and prioritized recommendations for improvement."}],why_choose_us:{title:"Detail Oriented",image:"/assets/images/home/history.png",points:["Certified Six Sigma Black Belts.","Data-driven approach utilizing process mining tools.","Focus on actionable, practical recommendations."]},faq:[{question:"How disruptive is the audit?",answer:"We minimize disruption by reviewing documentation and data first, then conducting targeted interviews."},{question:"What do we get at the end?",answer:"A comprehensive report detailing current state, issues, risks, and a roadmap for remediation."}]},"staff-augmentation":{title:"IT Staff Augmentation",subtitle:"Scale Your Team",description:"Add skilled operational talent to your team on demand.",icon:"bi bi-people-fill",hero_bg:"linear-gradient(135deg, #0f172a 0%, #06b6d4 100%)",hero_image:"/assets/images/people/women1.jpg",long_description:`
