        `,features:[{title:"Encryption",desc:"Bank-grade encryption for data at rest and in transit.",icon:"bi bi-safe2-fill"},{title:"File Recovery",desc:"Accidentally deleted a folder? Restore it yourself in seconds.",icon:"bi bi-recycle"},{title:"Granular Permissions",desc:"Control exactly which folders each user or group can see.",icon:"bi bi-people-fill"}],benefits:[{title:"No Hardware",description:"Retire that noisy, hot server in your closet.",icon:"bi bi-plug-fill"},{title:"Collaboration",description:"Stop emailing attachments. Share secure links instead.",icon:"bi bi-share-fill"},{title:"Mobile Ready",description:"Access everything from your phone or tablet.",icon:"bi bi-phone"}],process:[{step:"01",title:"Structure",description:"Design a logical folder hierarchy."},{step:"02",title:"Migrate",description:"Upload terabytes of data over weekends."},{step:"03",title:"Map",description:"Map drives on user computers for a seamless experience."}],why_choose_us:{title:"Data Sovereignty",image:"/assets/images/home/import.png",points:["Keep data within specific geographic regions if required.","Hybrid options available for large video/CAD files.","Ransomware detection built-in."]},faq:[{question:"Is it fast enough for large files?",answer:"For large files, we recommend a hybrid solution with a local cache."},{question:"Who owns the data?",answer:"You do. Always."}],content:""},"web-design":{title:"Web Design & Development",subtitle:"Digital Experience",description:"Stunning websites that convert visitors into customers.",icon:"bi bi-laptop",hero_bg:"linear-gradient(135deg, #034484 0%, #d946ef 100%)",hero_image:"/assets/images/home/websearch.png",long_description:`
